class Solution:
    def champagneTower(self, poured, query_row, query_glass):
        # Independent simulation using a flat list grown per row.
        cur = [float(poured)]
        for r in range(query_row):
            nxt = [0.0] * (r + 2)
            for j in range(r + 1):
                overflow = (cur[j] - 1.0) / 2.0
                if overflow > 0:
                    nxt[j] += overflow
                    nxt[j + 1] += overflow
            cur = nxt
        return min(1.0, max(0.0, cur[query_glass]))

