var champagneTower = function(poured, query_row, query_glass) {
    let row = [poured];
    for (let i = 0; i < query_row; i++) {
        const nxt = new Array(i + 2).fill(0);
        for (let j = 0; j < row.length; j++) {
            const excess = (row[j] - 1.0) / 2.0;
            if (excess > 0) {
                nxt[j] += excess;
                nxt[j + 1] += excess;
            }
        }
        row = nxt;
    }
    return Math.min(1.0, row[query_glass]);
};
